draw((-1,-1)--(-1,1)--(1,1)--(1,-1)--cycle);
draw(a--b--c--d--cycle);
label("$A$", a, N);
label("$B$", b, E);
label("$C$", c, S);
label("$D$", d, W);
[/asy]

